    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("Enter value for row %d, column %d: ", i + 1, j + 1);
            scanf("%d", &table[i][j]);
        }
    }

    // Display the table
    printf("\nGenerated Table:\n");
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%4d", table[i][j]);
        }
        printf("\n");  // Move to the next line after a row
    }

    return 0;
}
```

